const featuresStyles = "@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');\n\r\n  /* ============== TOKENS ============== */\r\n  :root {\r\n    --green: #4ea84e;\r\n    --green-bright: #5cb55c;\r\n    --green-dark: #163d2a;\r\n    --green-darker: #0f2e20;\r\n    --green-soft: #e8f3e6;\r\n    --cream: #f1ebd9;          /* warm cream — feature card bg */\r\n    --cream-2: #ebe5d2;\r\n    --cream-cool: #efece1;     /* cooler cream — alt sections */\r\n    --bg: #ffffff;\r\n    --gray-50: #f7f6f3;\r\n    --gray-100: #f1efea;\r\n    --gray-200: #e6e3dc;\r\n    --text: #1a1a1a;\r\n    --text-muted: #6b7280;\r\n    --border: #e7e4dc;\r\n    --warn: #d4842a;\r\n    --danger: #d94a4a;\r\n    --radius: 10px;\r\n    --radius-lg: 18px;\r\n    --shadow-sm: 0 2px 6px rgba(0,0,0,0.04);\r\n    --shadow-md: 0 6px 24px rgba(0,0,0,0.08);\r\n    --shadow-lg: 0 20px 50px rgba(0,0,0,0.15);\r\n    --maxw: 1180px;\r\n  }\r\n\r\n  /* ============== RESET ============== */\r\n  *, *::before, *::after { box-sizing: border-box; }\r\n  body {\r\n    margin: 0;\r\n    font-family: 'Inter', -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, sans-serif;\r\n    color: var(--text);\r\n    background: #fff;\r\n    line-height: 1.55;\r\n    -webkit-font-smoothing: antialiased;\r\n    font-size: 16px;\r\n  }\r\n  img { max-width: 100%; display: block; }\r\n  a { color: inherit; text-decoration: none; }\r\n  button { font-family: inherit; cursor: pointer; border: 0; background: none; }\r\n  h1, h2, h3, h4, h5 { margin: 0; line-height: 1.15; letter-spacing: -0.01em; font-weight: 700; }\r\n  p { margin: 0; }\r\n\r\n  .wrap { max-width: var(--maxw); margin: 0 auto; padding: 0 28px; }\r\n  .green { color: var(--green); }\r\n  .eyebrow {\r\n    color: var(--green);\r\n    font-weight: 700;\r\n    font-size: 0.78rem;\r\n    letter-spacing: 0.18em;\r\n    text-transform: uppercase;\r\n  }\r\n\r\n  /* ============== BUTTONS ============== */\r\n  .btn {\r\n    display: inline-flex; align-items: center; justify-content: center;\r\n    padding: 13px 22px;\r\n    border-radius: 8px;\r\n    font-weight: 600;\r\n    font-size: 0.95rem;\r\n    transition: transform 0.15s ease, box-shadow 0.15s ease, background 0.15s ease;\r\n    white-space: nowrap;\r\n  }\r\n  .btn-primary { background: var(--green); color: #fff; box-shadow: 0 2px 8px rgba(78,168,78,0.3); }\r\n  .btn-primary:hover { background: #449e44; transform: translateY(-1px); }\r\n  .btn-outline { background: #fff; color: var(--text); border: 1.5px solid var(--text); }\r\n  .btn-outline:hover { background: var(--text); color: #fff; }\r\n  .btn-sm { padding: 10px 18px; font-size: 0.9rem; }\r\n  .btn-xs { padding: 7px 12px; font-size: 0.82rem; }\r\n\r\n  /* ============== HEADER / NAV ============== */\r\n  .nav {\r\n    position: sticky; top: 0; z-index: 50;\r\n    background: rgba(255,255,255,0.95);\r\n    backdrop-filter: blur(8px);\r\n    border-bottom: 1px solid rgba(0,0,0,0.03);\r\n  }\r\n  .nav-inner {\r\n    display: flex; align-items: center; justify-content: space-between;\r\n    height: 76px;\r\n  }\r\n  .logo { display: flex; align-items: center; gap: 10px; }\r\n  .logo-mark { width: 38px; height: 38px; display: flex; align-items: center; justify-content: center; color: var(--green); }\r\n  .logo-text { display: flex; flex-direction: column; line-height: 1; }\r\n  .logo-text .pro {\r\n    font-weight: 800; font-size: 1.25rem; letter-spacing: 0.02em; color: var(--green-dark);\r\n  }\r\n  .logo-text .pro em { font-style: normal; color: var(--green); }\r\n  .logo-text .crm {\r\n    font-size: 0.68rem; letter-spacing: 0.5em; color: var(--green-dark);\r\n    margin-top: 4px; padding-top: 4px; border-top: 1px solid var(--green-dark);\r\n    font-weight: 600;\r\n  }\r\n  .nav-links {\r\n    display: flex; align-items: center; gap: 34px;\r\n    font-weight: 500; font-size: 0.95rem; color: var(--text);\r\n  }\r\n  .nav-links a {\r\n    display: inline-flex; align-items: center; gap: 4px;\r\n    padding: 6px 0;\r\n    border-bottom: 2px solid transparent;\r\n  }\r\n  .nav-links a.active {\r\n    color: var(--green-dark);\r\n    font-weight: 700;\r\n    border-bottom-color: var(--green);\r\n  }\r\n  .nav-links a:hover { color: var(--green); }\r\n  .nav-right { display: flex; align-items: center; gap: 18px; }\r\n  .nav-right .login { font-weight: 500; font-size: 0.95rem; }\r\n  .nav-right .login:hover { color: var(--green); }\r\n\r\n  /* ============== HERO ============== */\r\n  .hero {\r\n    position: relative;\r\n    overflow: hidden;\r\n    padding: 60px 0 70px;\r\n    background:\r\n      radial-gradient(ellipse at 80% 25%, rgba(255, 240, 200, 0.5) 0%, transparent 55%),\r\n      radial-gradient(ellipse at 5% 70%, rgba(120, 180, 100, 0.2) 0%, transparent 60%),\r\n      linear-gradient(180deg, #ece4cf 0%, #d5e0c0 35%, #b6cd96 70%, #88b56c 100%);\r\n  }\r\n  .hero::before {\r\n    /* house silhouette top-right */\r\n    content: \"\";\r\n    position: absolute;\r\n    top: 60px; right: 4%;\r\n    width: 340px; height: 180px;\r\n    background:\r\n      linear-gradient(180deg, transparent 40%, rgba(70, 60, 50, 0.2) 40%, rgba(80, 70, 60, 0.16) 65%, transparent 65%);\r\n    clip-path: polygon(20% 100%, 20% 50%, 50% 20%, 80% 50%, 80% 100%);\r\n    opacity: 0.6;\r\n    pointer-events: none;\r\n    filter: blur(0.5px);\r\n  }\r\n  .hero::after {\r\n    /* foliage row */\r\n    content: \"\";\r\n    position: absolute;\r\n    left: 0; right: 0; bottom: 0;\r\n    height: 80px;\r\n    background:\r\n      radial-gradient(ellipse 100px 60px at 10% 80%, #3b6d3b 0%, transparent 70%),\r\n      radial-gradient(ellipse 120px 70px at 30% 75%, #4a7a3a 0%, transparent 70%),\r\n      radial-gradient(ellipse 110px 65px at 55% 78%, #3d6d3d 0%, transparent 70%),\r\n      radial-gradient(ellipse 130px 70px at 78% 75%, #4e8245 0%, transparent 70%),\r\n      radial-gradient(ellipse 100px 60px at 95% 80%, #3b6d3b 0%, transparent 70%);\r\n    pointer-events: none;\r\n  }\r\n  .hero-inner {\r\n    position: relative; z-index: 2;\r\n    display: grid; grid-template-columns: 0.85fr 1.15fr; gap: 40px; align-items: center;\r\n  }\r\n  .hero h1 {\r\n    font-size: clamp(2.4rem, 4.5vw, 3.4rem);\r\n    font-weight: 700;\r\n    color: #18221a;\r\n    margin: 12px 0 22px;\r\n    line-height: 1.05;\r\n  }\r\n  .hero h1 .accent { color: var(--green); display: block; margin-top: 6px; }\r\n  .hero p.lede {\r\n    font-size: 1.02rem;\r\n    color: #2a3a30;\r\n    max-width: 440px;\r\n  }\r\n\r\n  /* ---------- Big dashboard mockup in hero ---------- */\r\n  .hero-dash {\r\n    background: #1c1c1c;\r\n    border-radius: 14px;\r\n    padding: 8px;\r\n    box-shadow: var(--shadow-lg);\r\n    width: 100%;\r\n    max-width: 620px;\r\n    margin-left: auto;\r\n  }\r\n  .hero-dash-screen {\r\n    background: #fff;\r\n    border-radius: 8px;\r\n    overflow: hidden;\r\n    display: grid;\r\n    grid-template-columns: 110px 1fr;\r\n    height: 380px;\r\n  }\r\n  .dash-side {\r\n    background: var(--green-dark);\r\n    color: #fff;\r\n    padding: 12px 8px;\r\n    font-size: 10px;\r\n  }\r\n  .dash-side .mini-logo {\r\n    display: flex; align-items: center; gap: 5px; padding: 4px 6px; margin-bottom: 10px;\r\n  }\r\n  .dash-side .mini-logo .mark { width: 16px; height: 16px; color: var(--green); }\r\n  .dash-side .mini-logo .label { font-size: 8.5px; font-weight: 800; letter-spacing: 0.04em; line-height: 1; }\r\n  .dash-side .mini-logo .label small { display: block; font-size: 5.5px; letter-spacing: 0.4em; opacity: 0.7; margin-top: 1.5px; }\r\n  .dash-side nav { display: flex; flex-direction: column; gap: 2px; }\r\n  .dash-side a {\r\n    display: flex; align-items: center; gap: 6px;\r\n    padding: 5px 6px; border-radius: 4px;\r\n    color: rgba(255,255,255,0.78);\r\n    font-size: 9.5px;\r\n  }\r\n  .dash-side a.active { background: rgba(255,255,255,0.12); color: #fff; }\r\n  .dash-side a svg { width: 10px; height: 10px; flex-shrink: 0; }\r\n\r\n  .dash-main { padding: 10px 12px; overflow: hidden; }\r\n  .dash-title { font-size: 0.95rem; font-weight: 700; margin-bottom: 8px; display: flex; justify-content: space-between; align-items: center; }\r\n  .dash-title .icons { display: flex; gap: 8px; align-items: center; color: var(--text-muted); }\r\n  .dash-title .ava { width: 18px; height: 18px; border-radius: 50%; background: linear-gradient(135deg, #d4b896, #8c6e50); }\r\n\r\n  .dash-stats { display: grid; grid-template-columns: repeat(4, 1fr); gap: 6px; margin-bottom: 8px; }\r\n  .dash-stat {\r\n    border: 1px solid var(--border);\r\n    border-radius: 5px;\r\n    padding: 6px 7px;\r\n  }\r\n  .dash-stat .label { font-size: 6.5px; letter-spacing: 0.1em; color: var(--text-muted); font-weight: 600; }\r\n  .dash-stat .num { font-size: 1rem; font-weight: 700; margin-top: 1px; }\r\n  .dash-stat .num.warn { color: var(--warn); }\r\n  .dash-stat .link { font-size: 6.5px; color: var(--green); margin-top: 1px; font-weight: 600; }\r\n\r\n  .dash-charts { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; }\r\n  .dash-panel {\r\n    border: 1px solid var(--border);\r\n    border-radius: 5px;\r\n    padding: 7px;\r\n    background: #fff;\r\n  }\r\n  .dash-panel h4 {\r\n    font-size: 8.5px; font-weight: 700; margin-bottom: 5px;\r\n    display: flex; justify-content: space-between; align-items: center;\r\n  }\r\n  .dash-panel h4 .meta { font-size: 6.5px; font-weight: 500; color: var(--text-muted); }\r\n  .dash-map {\r\n    height: 75px; border-radius: 3px;\r\n    background: linear-gradient(135deg, #e8f0e0 0%, #d8e6cc 100%);\r\n    overflow: hidden;\r\n    margin-bottom: 5px;\r\n  }\r\n  .dash-map svg { width: 100%; height: 100%; }\r\n  .dash-donut-row { display: flex; gap: 6px; align-items: center; margin-top: 4px; }\r\n  .dash-donut { width: 44px; height: 44px; flex-shrink: 0; }\r\n  .dash-legend { font-size: 6.5px; }\r\n  .dash-legend div { display: flex; align-items: center; gap: 4px; padding: 0.5px 0; }\r\n  .dash-legend .dot { width: 5px; height: 5px; border-radius: 50%; display: inline-block; }\r\n  .dash-legend .pct { margin-left: auto; font-weight: 600; }\r\n\r\n  .dash-line-chart { height: 80px; position: relative; margin-bottom: 4px; }\r\n  .chart-yaxis {\r\n    position: absolute; left: 0; top: 0; bottom: 0;\r\n    display: flex; flex-direction: column; justify-content: space-between;\r\n    font-size: 5.5px; color: var(--text-muted); padding: 2px 0;\r\n  }\r\n  .chart-xaxis {\r\n    display: flex; justify-content: space-between;\r\n    font-size: 6px; color: var(--text-muted); padding-left: 18px;\r\n  }\r\n  .upcoming-list { display: flex; flex-direction: column; gap: 3px; margin-top: 5px; }\r\n  .upcoming-item {\r\n    display: grid; grid-template-columns: 28px 1fr; gap: 4px;\r\n    padding: 3px 4px;\r\n    background: var(--green-soft);\r\n    border-radius: 3px;\r\n    font-size: 6.5px;\r\n  }\r\n  .upcoming-item .time { font-weight: 700; color: var(--green-dark); font-size: 6.5px; line-height: 1; }\r\n  .upcoming-item .time small { font-weight: 500; opacity: 0.7; }\r\n  .upcoming-item .addr { font-weight: 600; }\r\n  .upcoming-item .type { color: var(--text-muted); }\r\n\r\n  /* ============== FEATURE NAV STRIP ============== */\r\n  .feature-strip {\r\n    background: #fff;\r\n    border-radius: 12px;\r\n    box-shadow: 0 -1px 0 #fff, 0 -10px 30px rgba(0,0,0,0.04);\r\n    position: relative;\r\n    z-index: 5;\r\n    margin-top: -36px;\r\n    padding: 22px 14px;\r\n    display: grid;\r\n    grid-template-columns: repeat(7, 1fr);\r\n  }\r\n  .fstrip-cell {\r\n    text-align: center;\r\n    padding: 4px 6px;\r\n    border-right: 1px solid var(--border);\r\n    color: var(--text);\r\n  }\r\n  .fstrip-cell:last-child { border-right: 0; }\r\n  .fstrip-cell .ico { color: var(--green); margin-bottom: 8px; display: inline-flex; }\r\n  .fstrip-cell .label { font-size: 0.78rem; font-weight: 600; line-height: 1.2; }\r\n\r\n  /* ============== FEATURE BLOCKS ============== */\r\n  .features-stack {\r\n    padding: 60px 0 0;\r\n    display: flex; flex-direction: column; gap: 24px;\r\n  }\r\n  .feature-row {\r\n    border-radius: var(--radius-lg);\r\n    padding: 36px 40px;\r\n    display: grid;\r\n    grid-template-columns: 1.05fr 0.95fr;\r\n    gap: 50px;\r\n    align-items: center;\r\n  }\r\n  .feature-row.alt { background: var(--cream-cool); }\r\n  .feature-row.warm { background: var(--cream); }\r\n  .feature-row .copy h2 {\r\n    font-size: clamp(1.5rem, 2.6vw, 1.95rem);\r\n    margin: 12px 0 14px;\r\n    line-height: 1.2;\r\n  }\r\n  .feature-row .copy p { color: #4a4e48; margin-bottom: 22px; font-size: 0.95rem; max-width: 440px; }\r\n  .feature-list { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 8px; }\r\n  .feature-list li {\r\n    display: flex; align-items: center; gap: 10px;\r\n    font-weight: 500; font-size: 0.93rem;\r\n  }\r\n  .feature-list li svg { color: var(--green); flex-shrink: 0; }\r\n  .feature-row.text-right .copy { order: 2; }\r\n  .feature-row.text-right .mock { order: 1; }\r\n\r\n  /* ---------- SCHEDULE MOCKUP ---------- */\r\n  .mock-card {\r\n    background: #fff;\r\n    border-radius: 10px;\r\n    border: 1px solid var(--border);\r\n    overflow: hidden;\r\n    box-shadow: var(--shadow-sm);\r\n  }\r\n  .mock-head {\r\n    padding: 14px 16px 12px;\r\n    display: flex; justify-content: space-between; align-items: center;\r\n    border-bottom: 1px solid var(--border);\r\n  }\r\n  .mock-head h3 { font-size: 0.95rem; font-weight: 700; }\r\n  .mock-tabs { display: flex; gap: 2px; font-size: 0.78rem; }\r\n  .mock-tabs span {\r\n    padding: 5px 11px; border-radius: 5px; color: var(--text-muted); font-weight: 500; cursor: pointer;\r\n  }\r\n  .mock-tabs span.active { background: var(--gray-100); color: var(--text); font-weight: 600; }\r\n\r\n  .schedule-body { display: grid; grid-template-columns: 130px 1fr; }\r\n  .schedule-techs {\r\n    border-right: 1px solid var(--border);\r\n    padding: 12px 8px;\r\n  }\r\n  .schedule-techs .heading { font-size: 0.7rem; font-weight: 600; color: var(--text-muted); padding: 0 6px 8px; }\r\n  .tech-item {\r\n    display: flex; align-items: center; gap: 8px;\r\n    padding: 7px 6px;\r\n    border-radius: 5px;\r\n    font-size: 0.78rem;\r\n    margin-bottom: 2px;\r\n  }\r\n  .tech-item .dot { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }\r\n  .tech-item .name { font-weight: 600; flex: 1; }\r\n  .tech-item .count { font-weight: 600; color: var(--green); font-size: 0.74rem; }\r\n\r\n  .schedule-map {\r\n    background: linear-gradient(135deg, #eaf0e2 0%, #d7e3c7 100%);\r\n    height: 245px;\r\n    position: relative;\r\n    overflow: hidden;\r\n  }\r\n  .schedule-map .map-dates {\r\n    position: absolute; top: 10px; right: 14px;\r\n    display: flex; gap: 12px; font-size: 0.72rem; color: var(--text-muted);\r\n  }\r\n  .schedule-map svg { width: 100%; height: 100%; }\r\n\r\n  /* ---------- CUSTOMER PROFILE MOCKUP ---------- */\r\n  .cust-card { background: #fff; border-radius: 10px; padding: 18px 20px; box-shadow: var(--shadow-sm); border: 1px solid rgba(0,0,0,0.04); }\r\n  .cust-label { font-size: 0.72rem; color: var(--text-muted); font-weight: 600; margin-bottom: 12px; }\r\n  .cust-header { display: flex; gap: 14px; align-items: flex-start; margin-bottom: 16px; }\r\n  .cust-avatar {\r\n    width: 60px; height: 60px; border-radius: 8px;\r\n    background:\r\n      radial-gradient(ellipse at 60% 40%, rgba(255,235,180,0.5), transparent 60%),\r\n      linear-gradient(180deg, #c8d8a8 0%, #6a9a5a 50%, #3d6e34 100%);\r\n    flex-shrink: 0;\r\n    position: relative; overflow: hidden;\r\n  }\r\n  .cust-avatar::after {\r\n    content: \"\"; position: absolute; inset: 35% 20% 0 20%;\r\n    background: linear-gradient(180deg, #8c7560 0%, #6e5a48 100%);\r\n    clip-path: polygon(15% 100%, 15% 40%, 50% 10%, 85% 40%, 85% 100%);\r\n  }\r\n  .cust-info { flex: 1; }\r\n  .cust-name-row { display: flex; align-items: center; gap: 8px; margin-bottom: 6px; }\r\n  .cust-name { font-size: 1.05rem; font-weight: 700; }\r\n  .badge {\r\n    font-size: 0.68rem; font-weight: 600;\r\n    padding: 3px 9px; border-radius: 99px;\r\n  }\r\n  .badge.active { background: var(--green-soft); color: var(--green-dark); }\r\n  .badge.res { background: #ffe9d6; color: #b86b1a; }\r\n  .badge.green { background: var(--green-soft); color: var(--green-dark); }\r\n  .badge.warn { background: #fff3da; color: #b86b1a; }\r\n  .badge.danger { background: #fbe2e2; color: #b22020; }\r\n  .badge.gray { background: var(--gray-100); color: var(--text-muted); }\r\n  .badge.blue { background: #e3edfb; color: #2854a8; }\r\n  .cust-meta { font-size: 0.78rem; color: #4a4e48; line-height: 1.7; }\r\n  .cust-meta div { display: flex; align-items: center; gap: 6px; }\r\n  .cust-meta svg { color: var(--text-muted); flex-shrink: 0; }\r\n\r\n  .cust-tabs {\r\n    display: flex; gap: 4px;\r\n    border-bottom: 1px solid var(--border);\r\n    margin-bottom: 14px;\r\n    font-size: 0.82rem;\r\n  }\r\n  .cust-tabs span {\r\n    padding: 8px 10px; color: var(--text-muted); cursor: pointer;\r\n    border-bottom: 2px solid transparent;\r\n    font-weight: 500;\r\n  }\r\n  .cust-tabs span.active { color: var(--green); border-bottom-color: var(--green); font-weight: 700; }\r\n\r\n  .cust-body { display: grid; grid-template-columns: 1.2fr 1fr; gap: 16px; }\r\n  .cust-sect h5 { font-size: 0.75rem; font-weight: 700; margin-bottom: 8px; color: var(--text); }\r\n  .sv-row {\r\n    display: grid; grid-template-columns: auto 1fr auto;\r\n    gap: 8px; padding: 5px 0; font-size: 0.72rem;\r\n    border-top: 1px solid var(--border);\r\n    align-items: center;\r\n  }\r\n  .sv-row:first-of-type { border-top: 1px solid var(--border); }\r\n  .sv-row .dt { color: var(--text-muted); font-weight: 500; min-width: 60px; }\r\n  .note-card {\r\n    background: var(--gray-50); border-radius: 5px;\r\n    padding: 8px 10px; font-size: 0.72rem; color: #4a4e48;\r\n    line-height: 1.5;\r\n    margin-bottom: 8px;\r\n  }\r\n  .next-appt { font-size: 0.72rem; }\r\n  .next-appt strong { font-weight: 600; }\r\n\r\n  /* ---------- WORK ORDERS MOCKUP ---------- */\r\n  .wo-tabs {\r\n    display: flex; gap: 2px; padding: 10px 16px;\r\n    border-bottom: 1px solid var(--border);\r\n    font-size: 0.78rem;\r\n  }\r\n  .wo-tabs span {\r\n    padding: 5px 11px; border-radius: 5px;\r\n    font-weight: 500; color: var(--text-muted); cursor: pointer;\r\n  }\r\n  .wo-tabs span.active { background: var(--gray-100); color: var(--text); font-weight: 700; }\r\n  .wo-table { width: 100%; border-collapse: collapse; font-size: 0.82rem; }\r\n  .wo-table td {\r\n    padding: 14px 16px; border-top: 1px solid var(--border);\r\n  }\r\n  .wo-table tr:first-child td { border-top: 0; }\r\n  .wo-table .id { color: var(--text-muted); font-weight: 500; }\r\n  .wo-table .addr { font-weight: 600; }\r\n  .wo-table .type { font-size: 0.72rem; color: var(--text-muted); font-weight: 500; margin-top: 2px; }\r\n  .wo-table .tech { font-weight: 500; text-align: right; }\r\n\r\n  /* ---------- INVOICES MOCKUP ---------- */\r\n  .inv-stats { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; padding: 14px 16px; }\r\n  .inv-stat {\r\n    border: 1px solid var(--border); border-radius: 6px;\r\n    padding: 9px 11px;\r\n  }\r\n  .inv-stat .l { font-size: 0.62rem; color: var(--text-muted); letter-spacing: 0.12em; font-weight: 600; }\r\n  .inv-stat .v { font-size: 1.35rem; font-weight: 700; margin-top: 2px; }\r\n  .inv-stat .v.warn { color: var(--warn); }\r\n  .inv-stat .v.danger { color: var(--danger); }\r\n  .inv-stat .v.good { color: var(--green); }\r\n  .inv-stat .amt { font-size: 0.7rem; color: var(--text-muted); margin-top: 1px; font-weight: 500; }\r\n\r\n  .inv-table { width: 100%; border-collapse: collapse; font-size: 0.78rem; }\r\n  .inv-table th, .inv-table td { padding: 9px 16px; text-align: left; }\r\n  .inv-table th {\r\n    font-size: 0.65rem; letter-spacing: 0.08em; color: var(--text-muted);\r\n    font-weight: 600; text-transform: uppercase;\r\n    border-top: 1px solid var(--border); border-bottom: 1px solid var(--border);\r\n    background: #fafaf7;\r\n  }\r\n  .inv-table td { border-bottom: 1px solid var(--border); }\r\n  .inv-table tr:last-child td { border-bottom: 0; }\r\n  .inv-table .id { color: var(--text-muted); font-weight: 500; }\r\n  .inv-table .total { font-weight: 600; }\r\n  .inv-status { display: inline-block; padding: 3px 9px; border-radius: 99px; font-size: 0.68rem; font-weight: 600; }\r\n\r\n  .new-btn {\r\n    background: var(--green); color: #fff;\r\n    padding: 7px 12px; border-radius: 6px;\r\n    font-size: 0.78rem; font-weight: 600;\r\n    display: inline-flex; align-items: center; gap: 4px;\r\n  }\r\n\r\n  /* ============== CTA BANNER ============== */\r\n  .cta-banner { padding: 50px 0 70px; background: #fff; }\r\n  .cta-card {\r\n    background: var(--cream);\r\n    border-radius: var(--radius-lg);\r\n    padding: 26px 36px;\r\n    display: flex; align-items: center; gap: 24px;\r\n  }\r\n  .cta-card .leaf-shield {\r\n    width: 56px; height: 64px; flex-shrink: 0;\r\n    background: var(--green);\r\n    clip-path: polygon(50% 0%, 100% 12%, 100% 65%, 50% 100%, 0% 65%, 0% 12%);\r\n    display: flex; align-items: center; justify-content: center;\r\n    color: #fff;\r\n  }\r\n  .cta-card .copy { flex: 1; }\r\n  .cta-card .copy h3 { font-size: 1.3rem; margin-bottom: 6px; }\r\n  .cta-card .copy h3 .green { color: var(--green); }\r\n  .cta-card .copy p { color: var(--text-muted); font-size: 0.92rem; }\r\n  .cta-card .actions { display: flex; gap: 12px; flex-shrink: 0; }\r\n\r\n  /* ============== FOOTER ============== */\r\n  .footer {\r\n    background: var(--green-darker);\r\n    color: rgba(255,255,255,0.85);\r\n    padding: 50px 0 26px;\r\n    font-size: 0.92rem;\r\n  }\r\n  .footer-grid {\r\n    display: grid; grid-template-columns: 1.6fr 1fr 1fr 1fr 1fr;\r\n    gap: 30px; padding-bottom: 30px;\r\n  }\r\n  .footer-brand .logo .pro { color: #fff; }\r\n  .footer-brand .logo .pro em { color: var(--green-bright); }\r\n  .footer-brand .logo .crm { color: #fff; border-color: #fff; }\r\n  .footer-brand .logo .logo-mark { color: var(--green-bright); }\r\n  .footer-brand .tagline {\r\n    margin-top: 18px; color: rgba(255,255,255,0.75);\r\n    font-size: 0.85rem; line-height: 1.55; max-width: 260px;\r\n  }\r\n  .footer-socials { display: flex; gap: 12px; margin-top: 18px; }\r\n  .footer-socials a {\r\n    width: 30px; height: 30px; border-radius: 50%;\r\n    border: 1px solid rgba(255,255,255,0.35);\r\n    display: inline-flex; align-items: center; justify-content: center;\r\n    color: #fff; transition: background 0.15s;\r\n  }\r\n  .footer-socials a:hover { background: var(--green); border-color: var(--green); }\r\n  .footer h5 {\r\n    color: #fff; font-size: 0.78rem; font-weight: 700;\r\n    letter-spacing: 0.16em; margin-bottom: 16px; text-transform: uppercase;\r\n  }\r\n  .footer ul { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 10px; }\r\n  .footer ul a:hover { color: var(--green-bright); }\r\n  .footer-bottom {\r\n    border-top: 1px solid rgba(255,255,255,0.12);\r\n    padding-top: 18px;\r\n    display: flex; justify-content: space-between; align-items: center;\r\n    font-size: 0.82rem; color: rgba(255,255,255,0.7);\r\n  }\r\n  .footer-bottom .links { display: flex; gap: 28px; }\r\n\r\n  /* ============== RESPONSIVE ============== */\r\n  @media (max-width: 1080px) {\r\n    .nav-links { display: none; }\r\n    .hero-inner { grid-template-columns: 1fr; }\r\n    .hero-dash { max-width: 100%; margin-left: 0; }\r\n    .feature-strip { grid-template-columns: repeat(4, 1fr); gap: 14px; }\r\n    .fstrip-cell { border-right: 0; }\r\n    .feature-row { grid-template-columns: 1fr; padding: 28px 24px; gap: 28px; }\r\n    .feature-row.text-right .copy, .feature-row.text-right .mock { order: initial; }\r\n    .footer-grid { grid-template-columns: 1fr 1fr; }\r\n    .cta-card { flex-direction: column; text-align: center; }\r\n  }\r\n  @media (max-width: 640px) {\r\n    .wrap { padding: 0 20px; }\r\n    .hero-dash-screen { grid-template-columns: 90px 1fr; height: auto; min-height: 320px; }\r\n    .dash-stats { grid-template-columns: repeat(2, 1fr); }\r\n    .dash-charts { grid-template-columns: 1fr; }\r\n    .feature-strip { grid-template-columns: repeat(2, 1fr); }\r\n    .schedule-body { grid-template-columns: 1fr; }\r\n    .cust-body { grid-template-columns: 1fr; }\r\n    .inv-stats { grid-template-columns: 1fr 1fr; }\r\n    .inv-table th:nth-child(3), .inv-table td:nth-child(3),\r\n    .inv-table th:nth-child(4), .inv-table td:nth-child(4) { display: none; }\r\n    .footer-grid { grid-template-columns: 1fr; }\r\n    .footer-bottom { flex-direction: column; gap: 12px; }\r\n  }\r\n";

